# Base classes module - abstract base classes implementing interfaces

from types_module import Point, Dimension, Status, Priority
from interfaces_module import ITrackable, IMeasurable, INamed

@abstract
class WorkItem(ITrackable, INamed):
    _id: int
    _status: Status
    _name: str

    def __init__(self, id: int, name: str):
        self._id = id
        self._name = name
        self._status = Status.PENDING

    @virtual
    def get_id(self) -> int:
        return self._id

    @virtual
    def get_status(self) -> Status:
        return self._status

    @virtual
    def get_name(self) -> str:
        return self._name

    @virtual
    def set_status(self, new_status: Status) -> None:
        self._status = new_status

    @abstract
    def execute(self) -> bool: ...

class Shape(IMeasurable, INamed):
    _dimensions: Dimension

    def __init__(self, dims: Dimension):
        self._dimensions = dims

    @virtual
    def get_dimensions(self) -> Dimension:
        return self._dimensions

    @virtual
    def get_area(self) -> int:
        return self._dimensions.area()

    @virtual
    def get_name(self) -> str:
        return "Shape"
